```class Solution {
public:
    vector<string> findRepeatedDnaSequences(string s) {
        unordered_map<string, int> mp;
        vector<string> res;
        for (int i = 0; i <= s.size() - 10; i++) {
            string tmp = s.substr(i, 10);
            if (++mp[tmp] == 2) res.push_back(tmp);
        }
        return res;
    }
};
